<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Kanban Board</title>
    <style>
        *,
        *::before,
        *::after {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        :root {
            --bg: #f0f2f5;
            --card-bg: #ffffff;
            --col-todo-header: #4a90d9;
            --col-doing-header: #f5a623;
            --col-done-header: #7ed321;
            --text-primary: #1a1a2e;
            --text-secondary: #5a5a7a;
            --border: #e0e4ea;
            --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06), 0 1px 2px rgba(0, 0, 0, 0.04);
            --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.08), 0 2px 4px rgba(0, 0, 0, 0.04);
            --shadow-lg: 0 8px 24px rgba(0, 0, 0, 0.12), 0 4px 8px rgba(0, 0, 0, 0.06);
            --radius: 10px;
            --radius-sm: 6px;
            --transition: 0.2s ease;
        }

        body {
            font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
            background: var(--bg);
            min-height: 100vh;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 20px;
            color: var(--text-primary);
        }

        .app-container {
            width: 100%;
            max-width: 1100px;
            display: flex;
            flex-direction: column;
            gap: 24px;
        }

        /* ── Header / Add Card Area ── */
        .add-card-area {
            display: flex;
            gap: 12px;
            background: #fff;
            padding: 18px 20px;
            border-radius: var(--radius);
            box-shadow: var(--shadow-md);
            align-items: center;
        }

        .add-card-area label {
            font-weight: 600;
            font-size: 0.95rem;
            color: var(--text-secondary);
            white-space: nowrap;
            letter-spacing: 0.01em;
        }

        #new-card {
            flex: 1;
            padding: 11px 16px;
            border: 2px solid var(--border);
            border-radius: var(--radius-sm);
            font-size: 0.95rem;
            outline: none;
            transition: border-color var(--transition), box-shadow var(--transition);
            background: #fafbfc;
            color: var(--text-primary);
        }

        #new-card:focus {
            border-color: #4a90d9;
            box-shadow: 0 0 0 3px rgba(74, 144, 217, 0.12);
            background: #fff;
        }

        #new-card::placeholder {
            color: #b0b8c1;
        }

        #add-card {
            padding: 11px 22px;
            background: #4a90d9;
            color: #fff;
            border: none;
            border-radius: var(--radius-sm);
            font-size: 0.95rem;
            font-weight: 600;
            cursor: pointer;
            white-space: nowrap;
            letter-spacing: 0.02em;
            transition: background var(--transition), transform var(--transition), box-shadow var(--transition);
            box-shadow: 0 2px 6px rgba(74, 144, 217, 0.3);
        }

        #add-card:hover {
            background: #3a7bc8;
            transform: translateY(-1px);
            box-shadow: 0 4px 12px rgba(74, 144, 217, 0.35);
        }
        #add-card:active {
            transform: translateY(0);
            box-shadow: 0 2px 4px rgba(74, 144, 217, 0.25);
        }

        /* ── Board ── */
        .board {
            display: grid;
            grid-template-columns: 1fr 1fr 1fr;
            gap: 18px;
            align-items: start;
        }

        .column {
            background: #fff;
            border-radius: var(--radius);
            box-shadow: var(--shadow-md);
            display: flex;
            flex-direction: column;
            min-height: 400px;
            transition: box-shadow var(--transition), border-color var(--transition);
            border: 2px solid transparent;
            overflow: hidden;
        }

        .column.drag-over {
            border-color: #4a90d9;
            box-shadow: var(--shadow-lg), 0 0 0 4px rgba(74, 144, 217, 0.15);
            background: #f8faff;
        }

        .column-header {
            padding: 14px 18px;
            font-weight: 700;
            font-size: 1rem;
            letter-spacing: 0.02em;
            display: flex;
            align-items: center;
            justify-content: space-between;
            color: #fff;
            user-select: none;
        }

        #col-todo .column-header {
            background: var(--col-todo-header);
        }
        #col-doing .column-header {
            background: var(--col-doing-header);
        }
        #col-done .column-header {
            background: var(--col-done-header);
        }

        .column-header .count {
            background: rgba(255, 255, 255, 0.3);
            color: #fff;
            font-weight: 700;
            font-size: 0.85rem;
            padding: 4px 10px;
            border-radius: 20px;
            min-width: 28px;
            text-align: center;
            line-height: 1;
        }

        .card-container {
            flex: 1;
            padding: 10px 12px;
            display: flex;
            flex-direction: column;
            gap: 8px;
            min-height: 60px;
            background: #fafbfc;
            transition: background var(--transition);
        }

        .column.drag-over .card-container {
            background: #f0f4ff;
        }

        /* ── Cards ── */
        .card {
            background: var(--card-bg);
            border-radius: var(--radius-sm);
            padding: 12px 14px;
            box-shadow: var(--shadow-sm);
            cursor: grab;
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: 10px;
            transition: box-shadow var(--transition), transform var(--transition), opacity var(--transition);
            border: 1px solid var(--border);
            user-select: none;
            font-size: 0.9rem;
            line-height: 1.4;
            word-break: break-word;
        }

        .card:hover {
            box-shadow: var(--shadow-md);
            transform: translateY(-1px);
        }
        .card:active {
            cursor: grabbing;
        }
        .card.dragging {
            opacity: 0.5;
            transform: rotate(1deg) scale(0.97);
            box-shadow: var(--shadow-lg);
        }

        .card-title {
            flex: 1;
            min-width: 0;
            font-weight: 500;
            color: var(--text-primary);
        }

        .card-del {
            flex-shrink: 0;
            width: 28px;
            height: 28px;
            border-radius: 50%;
            border: none;
            background: transparent;
            color: #c0c7d0;
            font-size: 1rem;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: background var(--transition), color var(--transition);
            line-height: 1;
            font-weight: 700;
        }

        .card-del:hover {
            background: #ffeaea;
            color: #e04040;
        }
        .card-del:active {
            background: #ffd4d4;
        }

        /* ── Empty state hint ── */
        .card-container:empty::after {
            content: 'Drop cards here';
            display: block;
            text-align: center;
            color: #c5cdd8;
            font-size: 0.85rem;
            padding: 20px 0;
            pointer-events: none;
            font-style: italic;
        }

        /* ── Responsive ── */
        @media (max-width: 750px) {
            .board {
                grid-template-columns: 1fr;
                gap: 12px;
            }
            .add-card-area {
                flex-wrap: wrap;
            }
            #new-card {
                min-width: 100%;
            }
        }
    </style>
</head>
<body>
    <div class="app-container">
        <!-- Add Card Area -->
        <div class="add-card-area">
            <label for="new-card">New task</label>
            <input type="text" id="new-card" placeholder="What needs to be done?" maxlength="200">
            <button id="add-card">＋ Add Card</button>
        </div>

        <!-- Board -->
        <div class="board" id="board">
            <!-- To Do Column -->
            <div class="column" id="col-todo" data-col="todo">
                <div class="column-header">
                    <span>📋 To Do</span>
                    <span class="count">0</span>
                </div>
                <div class="card-container" id="container-todo"></div>
            </div>
            <!-- Doing Column -->
            <div class="column" id="col-doing" data-col="doing">
                <div class="column-header">
                    <span>⚡ Doing</span>
                    <span class="count">0</span>
                </div>
                <div class="card-container" id="container-doing"></div>
            </div>
            <!-- Done Column -->
            <div class="column" id="col-done" data-col="done">
                <div class="column-header">
                    <span>✅ Done</span>
                    <span class="count">0</span>
                </div>
                <div class="card-container" id="container-done"></div>
            </div>
        </div>
    </div>

    <script>
        (function () {
            // ── DOM refs ──
            const newCardInput = document.getElementById('new-card');
            const addCardBtn = document.getElementById('add-card');
            const boardEl = document.getElementById('board');
            const columns = {
                todo: {
                    columnEl: document.getElementById('col-todo'),
                    containerEl: document.getElementById('container-todo'),
                    countEl: document.getElementById('col-todo').querySelector('.count'),
                },
                doing: {
                    columnEl: document.getElementById('col-doing'),
                    containerEl: document.getElementById('container-doing'),
                    countEl: document.getElementById('col-doing').querySelector('.count'),
                },
                done: {
                    columnEl: document.getElementById('col-done'),
                    containerEl: document.getElementById('container-done'),
                    countEl: document.getElementById('col-done').querySelector('.count'),
                },
            };

            const STORAGE_KEY = 'kanban_board_state_v1';

            // ── State ──
            // Structure: { todo: ['card text', ...], doing: [...], done: [...] }
            let boardState = { todo: [], doing: [], done: [] };

            // ── Persistence ──
            function loadState() {
                try {
                    const raw = localStorage.getItem(STORAGE_KEY);
                    if (raw) {
                        const parsed = JSON.parse(raw);
                        // Validate shape
                        if (
                            parsed &&
                            Array.isArray(parsed.todo) &&
                            Array.isArray(parsed.doing) &&
                            Array.isArray(parsed.done)
                        ) {
                            boardState = parsed;
                        }
                    }
                } catch (e) {
                    // Corrupt data — reset
                    boardState = { todo: [], doing: [], done: [] };
                }
            }

            function saveState() {
                try {
                    localStorage.setItem(STORAGE_KEY, JSON.stringify(boardState));
                } catch (e) {
                    // Storage full or unavailable — silently fail
                }
            }

            // ── Render ──
            function renderAllColumns() {
                for (const colKey of ['todo', 'doing', 'done']) {
                    renderColumn(colKey);
                }
            }

            function renderColumn(colKey) {
                const col = columns[colKey];
                const cards = boardState[colKey];
                // Clear container
                col.containerEl.innerHTML = '';
                // Build cards
                for (let i = 0; i < cards.length; i++) {
                    const cardText = cards[i];
                    const cardEl = createCardElement(cardText, colKey, i);
                    col.containerEl.appendChild(cardEl);
                }
                // Update count
                col.countEl.textContent = cards.length;
            }

            function updateCounts() {
                for (const colKey of ['todo', 'doing', 'done']) {
                    columns[colKey].countEl.textContent = boardState[colKey].length;
                }
            }

            // ── Create card DOM element ──
            function createCardElement(cardText, colKey, index) {
                const card = document.createElement('div');
                card.className = 'card';
                card.draggable = true;
                card.dataset.col = colKey;
                card.dataset.index = index;
                card.dataset.text = cardText;

                // Title span
                const titleSpan = document.createElement('span');
                titleSpan.className = 'card-title';
                titleSpan.textContent = cardText;
                card.appendChild(titleSpan);

                // Delete button
                const delBtn = document.createElement('button');
                delBtn.className = 'card-del';
                delBtn.textContent = '✕';
                delBtn.title = 'Delete card';
                delBtn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    e.preventDefault();
                    deleteCard(colKey, index);
                });
                card.appendChild(delBtn);

                // Drag events
                card.addEventListener('dragstart', handleDragStart);
                card.addEventListener('dragend', handleDragEnd);

                return card;
            }

            // ── Card operations ──
            function addCard() {
                const text = newCardInput.value.trim();
                if (!text) return;
                boardState.todo.push(text);
                saveState();
                renderColumn('todo');
                updateCounts();
                newCardInput.value = '';
                newCardInput.focus();
            }

            function deleteCard(colKey, index) {
                if (index < 0 || index >= boardState[colKey].length) return;
                boardState[colKey].splice(index, 1);
                saveState();
                renderColumn(colKey);
                updateCounts();
            }

            function moveCard(fromCol, fromIndex, toCol) {
                if (fromIndex < 0 || fromIndex >= boardState[fromCol].length) return;
                const [cardText] = boardState[fromCol].splice(fromIndex, 1);
                boardState[toCol].push(cardText);
                saveState();
                renderColumn(fromCol);
                renderColumn(toCol);
                updateCounts();
            }

            // ── Drag and Drop ──
            let draggedCardData = null; // { col, index }

            function handleDragStart(e) {
                const card = e.target.closest('.card');
                if (!card) return;
                draggedCardData = {
                    col: card.dataset.col,
                    index: parseInt(card.dataset.index, 10),
                };
                card.classList.add('dragging');
                // Set data for HTML5 DnD (required for Firefox)
                e.dataTransfer.setData('text/plain', '');
                e.dataTransfer.effectAllowed = 'move';
            }

            function handleDragEnd(e) {
                const card = e.target.closest('.card');
                if (card) {
                    card.classList.remove('dragging');
                }
                // Remove drag-over class from all columns
                for (const colKey of ['todo', 'doing', 'done']) {
                    columns[colKey].columnEl.classList.remove('drag-over');
                }
                draggedCardData = null;
            }

            // Attach dragover + drop to each column element
            for (const colKey of ['todo', 'doing', 'done']) {
                const colEl = columns[colKey].columnEl;

                colEl.addEventListener('dragover', (e) => {
                    e.preventDefault();
                    e.dataTransfer.dropEffect = 'move';
                    colEl.classList.add('drag-over');
                });

                colEl.addEventListener('dragleave', (e) => {
                    // Only remove if we actually left the column (not entering a child)
                    if (!colEl.contains(e.relatedTarget)) {
                        colEl.classList.remove('drag-over');
                    }
                });

                colEl.addEventListener('drop', (e) => {
                    e.preventDefault();
                    colEl.classList.remove('drag-over');
                    if (!draggedCardData) return;
                    const { col: fromCol, index: fromIndex } = draggedCardData;
                    const toCol = colKey;
                    // Prevent no-op drops (same column)
                    if (fromCol === toCol) {
                        // Could reorder, but spec says move between columns — still, let's allow same-column reordering by moving to end
                        if (boardState[fromCol].length <= 1) {
                            draggedCardData = null;
                            return;
                        }
                        // Move to end of same column
                        const cardText = boardState[fromCol].splice(fromIndex, 1)[0];
                        boardState[fromCol].push(cardText);
                        saveState();
                        renderColumn(fromCol);
                        updateCounts();
                    } else {
                        moveCard(fromCol, fromIndex, toCol);
                    }
                    draggedCardData = null;
                });
            }

            // ── Prevent default drag behavior on card containers to allow drops ──
            for (const colKey of ['todo', 'doing', 'done']) {
                columns[colKey].containerEl.addEventListener('dragover', (e) => {
                    e.preventDefault();
                    e.dataTransfer.dropEffect = 'move';
                });
                columns[colKey].containerEl.addEventListener('drop', (e) => {
                    e.preventDefault();
                    // The column-level handler will catch it via bubbling
                });
            }

            // ── Add card button & Enter key ──
            addCardBtn.addEventListener('click', addCard);
            newCardInput.addEventListener('keydown', (e) => {
                if (e.key === 'Enter') {
                    e.preventDefault();
                    addCard();
                }
            });

            // ── Initialize ──
            loadState();
            renderAllColumns();
            updateCounts();
            newCardInput.focus();
        })();
    </script>
</body>
</html>
